    const colKey = ganttColKey(v), colHex = softHex(ganttColHex(v)), light = ((ganttColorMode === 'status' && colKey === 'hgrau') || ganttSoftLight()) ? ' g-light' : '';
    const isAuto = autoSpanned(v);
