// Absender/Büro (Eingabeadresse) – Default/Fallback; editierbar via Einstellungen → state.buero
const BUERO = {
  firma: 'P. Hefti Bauberatung GmbH',
  strasse: 'Bernstrasse 40',
  plzort: '3076 Worb',
  tel: '031 839 00 77',
  email: 'info@heftibb.ch',
  mwst: 8.1,            // MwSt-Satz in %
  preiseInkl: false,    // false = Beträge netto (exkl. MwSt), true = inkl.
  archZuschlag: 15,     // üblicher Architekten-/Bauleitungszuschlag in % auf den Nettobetrag vor MwSt
};
// MwSt-Konvention (global, aus den Büro-Einstellungen)
function mwstSatz() { const v = Number((state.buero || BUERO).mwst); return (isFinite(v) && v >= 0) ? v : 8.1; }
function archZuschlagP() { const v = Number((state.buero || BUERO).archZuschlag); return (isFinite(v) && v >= 0) ? v : 15; }
// Netto eines Auswahlentscheids: aus Offerte-Brutto − Rabatt − Skonto, sonst altes Ist-Feld
function entHasIst(e) { return (e.brutto != null && e.brutto !== '') || (e.ist != null && e.ist !== ''); }
function entNetto(e) {
  if (e.brutto != null && e.brutto !== '') { const n = condNetto({ brutto: e.brutto, rabatt: e.rabatt, skonto: e.skonto, weitereAbz: 0 }); return n || 0; }
  if (e.ist != null && e.ist !== '') return Number(e.ist) || 0;
  return 0;
}
// Vergleich Budget (WV) ↔ nach Auswahl; Mehr-/Minderkosten Δ + Architektenzuschlag + MwSt = vom Eigentümer
function eigKosten(ents) {
  const budgetWV = ents.reduce((a, e) => a + (Number(e.budget) || 0), 0);
  const nachAuswahl = ents.reduce((a, e) => a + (entHasIst(e) ? entNetto(e) : (Number(e.budget) || 0)), 0);
  const delta = ents.reduce((a, e) => a + (entHasIst(e) ? (entNetto(e) - (Number(e.budget) || 0)) : 0), 0);
  const z = archZuschlagP(), mw = mwstSatz();
  const zBetrag = delta * z / 100, deltaZ = delta + zBetrag, mwBetrag = deltaZ * mw / 100, brutto = deltaZ + mwBetrag;
  return { budgetWV, nachAuswahl, delta, z, zBetrag, deltaZ, mw, mwBetrag, brutto, netto: nachAuswahl, budget: budgetWV };
}
function preiseInkl() { return !!((state.buero || BUERO).preiseInkl); }
function mwstNote() { return preiseInkl() ? `inkl. ${mwstSatz()} % MwSt` : `Beträge exkl. MwSt (zzgl. ${mwstSatz()} %)`; }
function inklMwst(netto) { return preiseInkl() ? (Number(netto) || 0) : (Number(netto) || 0) * (1 + mwstSatz() / 100); }

function pdfDeckblatt(pid, vid, eid, typ) {
  const p = findProjekt(pid); const v = findVergabe(p, vid);
  const e = eid ? (v.eingeladene || []).find(x => x.id === eid) : null;
  const istOfferte = typ === 'offerte';
  const b = state.buero || BUERO;
  const titel = istOfferte ? 'Offerte – äusserste Konditionen' : 'Submissionseinladung';
  const frist = (e && e.frist) || v.frist;   // Unternehmer-Frist hat Vorrang
  const fristJahr = (dISO(frist) || new Date()).getFullYear();
  const termin = v.ausfuehrung ? v.ausfuehrung : ((v.bauStart && v.bauEnde) ? `${fmtDate(v.bauStart)} – ${fmtDate(v.bauEnde)}` : 'gem. Terminprogramm');
  const line = '...........................................';

  // Firma-Block: bei Offerte/known firma vorausgefüllt, sonst leer zum Ausfüllen
  const firmaBlock = e
    ? `<strong>${esc(e.firma)}</strong>${e.email ? '<br>' + esc(e.email) : ''}`
    : `Unternehmer, Firma<br>Strasse<br>PLZ/Ort<br>Tel./E-Mail<br>Sachbearbeiter/in`;

  const preisZeile = (label, fr) => `<tr><td>${label}</td><td class="pr">Fr.&nbsp; ${fr || line}</td></tr>`;
  const vorOff = istOfferte && e && e.betrag != null;   // bei Offerte ggf. Betrag vorausfüllen

  const html = `<!DOCTYPE html><html lang="de"><head><meta charset="utf-8"><title>${esc(titel)} – ${esc(v.gewerk)}</title>
  <style>
    * { box-sizing: border-box; }
    body { font-family: 'Segoe UI', Arial, sans-serif; color: #1b2533; margin: 26mm 22mm; font-size: 12.5px; line-height: 1.5; }
    .lh { color: #444; font-size: 11px; margin-bottom: 26px; }
    .lh .f { font-weight: 700; color: #1b2533; font-size: 14px; margin-bottom: 3px; }
    table.kv { width: 100%; border-collapse: collapse; }
    table.kv td { vertical-align: top; padding: 5px 0; }
    table.kv td.l { width: 38%; }
    .box { border: 1px solid #1b2533; padding: 7px 10px; margin: 2px 0; min-height: 22px; }
    .box.firma { min-height: 90px; }
    h1 { font-size: 16px; margin: 0 0 18px; }
    table.preis { width: 100%; border-collapse: collapse; margin-top: 4px; }
    table.preis td { padding: 6px 0; }
    table.preis td.pr { text-align: left; font-variant-numeric: tabular-nums; }
    .tot td { border-top: 2px solid #1b2533; font-weight: 700; }
    .fest { font-weight: 700; text-decoration: underline; margin-top: 22px; }
    .sig { display: flex; justify-content: space-between; margin-top: 40px; }
    .sig div { border-top: 1px solid #1b2533; width: 44%; padding-top: 4px; font-size: 11px; }
  </style></head><body>
    <div class="lh">
      ${b.logo ? `<img src="${b.logo}" alt="" style="max-height:64px;max-width:220px;display:block;margin-bottom:10px">` : ''}
      <div class="f">${esc(b.firma)}</div>
      ${esc(b.strasse)}${b.strasse ? '<br>' : ''}${esc(b.plzort)}${b.plzort ? '<br>' : ''}
      ${b.tel ? 'Tel. ' + esc(b.tel) + '<br>' : ''}${esc(b.email)}
    </div>

    <h1>${esc(titel)}</h1>

    <table class="kv">
      <tr><td class="l"><strong>Objekt:</strong></td><td><strong>${esc(p.name)}</strong><br>${esc(p.ort)}</td></tr>
      <tr><td class="l">Bauherr:</td><td>${esc(p.bauherr)}</td></tr>
      <tr><td class="l">Eingabeadresse:</td><td>${esc(b.firma)}${b.plzort ? '<br>' + esc(b.plzort) : ''}</td></tr>
      <tr><td class="l">Angebot für:</td><td><div class="box"><strong>BKP ${esc(v.bkp)} – ${esc(v.gewerk)}</strong></div></td></tr>
      <tr><td class="l">${istOfferte ? 'Unternehmer:' : 'Unternehmer, Firma:'}</td><td><div class="box firma">${firmaBlock}</div></td></tr>
      <tr><td class="l">Eingabefrist:</td><td><div class="box"><strong>${frist ? fmtDate(frist) : '—'}</strong></div></td></tr>
      <tr><td class="l">Voraussichtlicher Ausführungstermin:</td><td>${esc(termin)}</td></tr>
    </table>

    <table class="preis">
      ${preisZeile('Betrag ohne MwSt:', vorOff ? money(e.betrag) : '')}
      ${preisZeile('Rabatt&nbsp;&nbsp;.......... %', '')}
      ${preisZeile('Skonto&nbsp;&nbsp;.......... %', '')}
      ${preisZeile('Allg. Abzüge&nbsp;&nbsp;1 %', '')}
      <tr><td>Netto</td><td class="pr">Fr.&nbsp; ${line}</td></tr>
      ${preisZeile('MwSt&nbsp;&nbsp;8.1 %', '')}
      <tr class="tot"><td>Nettobetrag inkl. MwSt</td><td class="pr">Fr.&nbsp; ${line}</td></tr>
    </table>

    <div class="fest">Preise fest bis 31.12.${fristJahr}</div>

    <div class="sig"><div>Ort, Datum</div><div>Unterschrift</div></div>
    <script>window.onload=function(){setTimeout(function(){window.print();},250);};<\/script>
  </body></html>`;

  const w = window.open('', '_blank');
  if (!w) { toast('Bitte Popups für PDF erlauben', 'info'); return; }
  w.document.write(html); w.document.close();
}

/* --- Termine / Gantt --- */

function actEditTermin(pid, vid, defStart) {
  const p = findProjekt(pid); const v = findVergabe(p, vid);
  const sV = v.bauStart || defStart || '', eV = v.bauEnde || (defStart ? addDays(defStart, 5) : '');
  openModal('Grobtermine – ' + v.gewerk, `
    <div class="form-row">
      <label class="field">Ausführung von <input class="input" type="date" id="t_start" value="${esc(sV)}"></label>
      <label class="field">Ausführung bis <input class="input" type="date" id="t_ende" value="${esc(eV)}"></label>
    </div>
    <div class="form-row" style="margin-top:8px">
      <label class="field">Bestellfrist / Vorlauf (Tage <b>vor</b> Start) <input class="input" type="number" id="t_bestell" value="${v.bestellfrist ?? ''}" placeholder="z.B. 30" min="0">
        <span class="muted" style="font-size:11px;font-weight:400;display:block;margin-top:3px">Material bestellen, Lieferfrist – heller Balken <b>vor</b> dem Hauptbalken.</span></label>
      <label class="field">Nachlauf / Austrocknung (Tage <b>nach</b> Ende) <input class="input" type="number" id="t_nach" value="${v.nachfrist ?? ''}" placeholder="z.B. 21" min="0">
        <span class="muted" style="font-size:11px;font-weight:400;display:block;margin-top:3px">z.B. Unterlagsboden trocknen – Balken <b>nach</b> dem Hauptbalken (Fläche erst danach frei).</span></label>
    </div>
    <label class="field" style="margin-top:4px">Bezeichnung Nachlauf <input class="input" id="t_nachlbl" value="${esc(v.nachfristLabel || '')}" placeholder="z.B. Austrocknung"></label>
    <div class="form-row" style="margin-top:12px">
      <label class="field">Vorab-Termin mit Unternehmer <input class="input" id="t_vlabel" value="${esc((v.vorab && v.vorab.label) || '')}" placeholder="z.B. Begehung / Startsitzung"></label>
      <label class="field">Tage vor Start <input class="input" type="number" id="t_vtage" value="${(v.vorab && v.vorab.tageVor != null) ? v.vorab.tageVor : ''}" placeholder="z.B. 7" min="0"></label>
    </div>
    <span class="muted" style="font-size:11px;display:block;margin-top:2px">Markiert im Gantt einen 📌 Vorab-Termin (Begehung/Kickoff) und erscheint im Kalender. Leer = kein Vorab-Termin.</span>
    ${(v.vorgaenge || []).length ? `<label class="field" style="flex-direction:row;align-items:center;gap:8px;margin-top:10px"><input type="checkbox" id="t_auto"${v.autoBalken ? ' checked' : ''}> Dauer <b>automatisch aus den Unterterminen</b> (Oberbalken umspannt sie)</label>` : ''}
    <label class="field" style="flex-direction:row;align-items:center;gap:8px;margin-top:10px"><input type="checkbox" id="t_erf"${v.erfuellt ? ' checked' : ''}> <b>Erfüllt / erledigt</b> (Häkchen im Balken)</label>
    <label class="field" style="margin-top:6px">Notiz / Terminänderung <input class="input" id="t_notiz" value="${esc(v.notiz || '')}" placeholder="z.B. Ausführung KW24 verschoben auf KW26 · geht wahrscheinlich bis KW24+2"></label>
  `, `${(v.bauStart && v.bauEnde) ? `<button class="btn ghost danger" data-act="termin-clear" data-pid="${pid}" data-vid="${vid}">Termin entfernen</button>` : ''}<button class="btn ghost" data-close="1">Abbrechen</button><button class="btn" data-act="save-termin" data-pid="${pid}" data-vid="${vid}">💾 Speichern</button>`);
}

function saveTermin(pid, vid) {
  if (gesperrt(pid)) { closeModal(); return; }
  const p = findProjekt(pid); const v = findVergabe(p, vid);
  const auto = $('#t_auto') ? $('#t_auto').checked : v.autoBalken;
  v.autoBalken = !!auto;
  { const ce = $('#t_erf'); if (ce) v.erfuellt = ce.checked; const cn = $('#t_notiz'); if (cn) v.notiz = cn.value.trim(); }
  if (!auto) {
    const s = $('#t_start').value, e = $('#t_ende').value;
    if (s && e && e < s) { toast('Ende liegt vor dem Start', 'info'); return; }
    v.bauStart = s; v.bauEnde = e;
  } else { recalcAutoBalken(v); }
  const bf = $('#t_bestell'); if (bf) v.bestellfrist = Number(bf.value) || 0;
  const nf = $('#t_nach'); if (nf) v.nachfrist = Number(nf.value) || 0;
  const nl = $('#t_nachlbl'); if (nl) v.nachfristLabel = nl.value.trim();
  const vl = $('#t_vlabel'), vt = $('#t_vtage');
  if (vl && vt) { const tage = vt.value.trim(); if (tage !== '' && !isNaN(+tage)) v.vorab = { label: vl.value.trim() || 'Vorab-Termin', tageVor: Math.max(0, Math.round(+tage)) }; else v.vorab = null; }
  save(); closeModal(); rerenderGantt(pid);
  toast('Termine aktualisiert');
}

function actNewVorgang(pid, vid) {
  const p = findProjekt(pid); const v = findVergabe(p, vid);
  openModal('Vorgang hinzufügen – ' + v.gewerk, `
    <label class="field">Bezeichnung <input class="input" id="o_titel" placeholder="z.B. Rohbau EG"></label>
    <div class="form-row">
      <label class="field">Von <input class="input" type="date" id="o_start" value="${esc(v.bauStart || '')}"></label>
      <label class="field">Bis <input class="input" type="date" id="o_ende" value="${esc(v.bauEnde || '')}"></label>
    </div>
  `, `<button class="btn ghost" data-close="1">Abbrechen</button><button class="btn" data-act="save-vorgang" data-pid="${pid}" data-vid="${vid}">Hinzufügen</button>`);
}

function saveVorgang(pid, vid) {
  if (gesperrt(pid)) { closeModal(); return; }
  const p = findProjekt(pid); const v = findVergabe(p, vid);
  const titel = $('#o_titel').value.trim();
  const s = $('#o_start').value, e = $('#o_ende').value;
  if (!titel) { toast('Bitte eine Bezeichnung eingeben', 'info'); return; }
  if (!s || !e) { toast('Bitte Start und Ende setzen', 'info'); return; }
  if (e < s) { toast('Ende liegt vor dem Start', 'info'); return; }
  (v.vorgaenge = v.vorgaenge || []).push({ id: uid('o'), titel, start: s, ende: e });
  recalcAutoBalken(v); save(); closeModal(); rerenderGantt(pid);
  toast('Vorgang hinzugefügt');
}

function removeVorgang(pid, vid, oid) {
  if (gesperrt(pid)) return;
  const p = findProjekt(pid); const v = findVergabe(p, vid);
  v.vorgaenge = (v.vorgaenge || []).filter(x => x.id !== oid);
  recalcAutoBalken(v); save(); rerenderGantt(pid);
}

