// Generische Handelsregister-Suche (LINDAS): Eingabe + „Suchen"-Knopf → Loader → Ergebnisse; onPick(f) bei Auswahl
function attachFirmaRegisterSuche(inputId, boxId, onPick, btnId) {
  const inp = $('#' + inputId), box = $('#' + boxId), btn = btnId ? $('#' + btnId) : null;
  if (!inp || !box) return;
  let matches = [];
  const renderResults = () => {
    box.style.display = 'block';
    if (!matches.length) { box.innerHTML = '<div class="ac-item muted">Keine Treffer im Handelsregister.</div>'; return; }
    box.innerHTML = matches.map((f, i) => `
      <div class="ac-item" data-i="${i}">
        <div><strong>${esc(f.name)}</strong>${f.rechtsform ? ` <span class="tag">${esc(f.rechtsform)}</span>` : ''}</div>
        <div class="muted" style="font-size:12px">${esc(f.uid)}${f.ort ? ' · ' + (f.plz ? esc(f.plz) + ' ' : '') + esc(f.ort) : ''}${f.branche ? ' · ' + esc(f.branche) : ''}</div>
      </div>`).join('');
  };
  const runSearch = async () => {
    const v = inp.value.trim();
    box.style.display = 'block';
    if (v.length < 3) { box.innerHTML = '<div class="ac-item muted">Bitte mindestens 3 Zeichen eingeben.</div>'; return; }
    box.innerHTML = `<div class="hr-loader"><span class="hr-spin"></span><span>Durchsuche das Handelsregister<span class="hr-dots"><i>.</i><i>.</i><i>.</i></span></span></div>`;
    const res = await firmenSuche(v);
    if (inp.value.trim() !== v) return;   // Eingabe hat sich geändert → Ergebnis verwerfen
    matches = res; renderResults();
  };
  if (btn) btn.addEventListener('click', runSearch);
  inp.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); runSearch(); } });
  box.addEventListener('click', e => {
    const it = e.target.closest('.ac-item'); if (!it || it.dataset.i == null) return;
    box.style.display = 'none'; box.innerHTML = '';
    onPick(matches[+it.dataset.i]);
  });
}
function attachFirmaSuche() {
  attachFirmaRegisterSuche('f_firma', 'firmaResults', f => {
    $('#f_firma').value = f.name; $('#f_uid').value = f.uid || ''; $('#f_rf').value = f.rechtsform || '';
    if (f.strasse && $('#f_str')) $('#f_str').value = f.strasse;
    $('#f_plz').value = f.plz || ''; $('#f_kort').value = f.ort || '';
    if (!$('#f_kat').value.trim()) $('#f_kat').value = f.branche || '';
    $('#f_person')?.focus(); toast('Firmendaten aus Register übernommen', 'info');
  }, 'f_firma_btn');
}
function saveKontakt(kid) {
  const firma = $('#f_firma').value.trim();
  if (!firma) { toast('Bitte eine Firma eingeben', 'info'); return; }
  const data = {
    firma, uid_nr: $('#f_uid').value.trim(), rechtsform: $('#f_rf').value.trim(),
    kategorie: $('#f_kat').value.trim() || '–', strasse: $('#f_str').value.trim(),
    plz: $('#f_plz').value.trim(), ort: $('#f_kort').value.trim(),
    person: $('#f_person').value.trim(), funktion: $('#f_funktion').value.trim(),
    email: $('#f_email').value.trim(), telefon: $('#f_tel').value.trim(),
    website: $('#f_web').value.trim(), notiz: $('#f_notiz').value.trim(),
    bkps: ($('#f_bkps') ? $('#f_bkps').value.split(',').map(s => s.trim()).filter(Boolean) : []),
  };
  const k = kid ? (state.kontakte || []).find(x => x.id === kid) : null;
  if (k) Object.assign(k, data); else state.kontakte.unshift({ id: uid('k'), ...data });
  save(); closeModal();
  if (kid) viewKontaktDetail(kid); else viewKontakte();
  toast('Kontakt gespeichert');
}

function exportData() {
  const blob = new Blob([JSON.stringify(state, null, 2)], { type: 'application/json' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'submitone-export.json';
  a.click();
  URL.revokeObjectURL(a.href);
  toast('Export erstellt');
}
// Voll-Backup wieder einlesen (ersetzt ALLE Daten) – oder einzelnes .gerber-Projekt
async function importData() {
  const data = await openGerber(); if (!data) return;
  if (Array.isArray(data.projekte)) {
    if (!confirm('Backup einlesen?\n\nErsetzt ALLE aktuellen Daten in diesem Browser (' + data.projekte.length + ' Projekte, ' + (data.kontakte || []).length + ' Kontakte). Aktueller Stand geht verloren.')) return;
    state = { projekte: data.projekte, kontakte: data.kontakte || [], dokumente: data.dokumente || [], buero: data.buero || state.buero };
    migrate(); save(); closeModal(); router();
    toast('Backup eingelesen (' + state.projekte.length + ' Projekte)', 'ok');
  } else if (data.typ === 'projekt' || data.format === 'gerber' || data.name || data.projekt) {
    addProjektFromGerber(data);   // einzelnes Projekt
  } else { toast('Keine gültige Backup- oder Projektdatei', 'info'); }
}

// --- .gerber Dateien: speichern/öffnen (File System Access API mit Download/Upload-Fallback) ---
async function saveGerber(filename, dataObj) {
  const json = JSON.stringify(dataObj, null, 2);
  if (window.showSaveFilePicker) {
    try {
      const handle = await window.showSaveFilePicker({ suggestedName: filename, types: [{ description: 'Gerber Datei', accept: { 'application/json': ['.gerber'] } }] });
      const w = await handle.createWritable(); await w.write(json); await w.close();
      toast('Gespeichert: ' + handle.name, 'ok'); return;
    } catch (err) { if (err && err.name === 'AbortError') return; }
  }
  const blob = new Blob([json], { type: 'application/json' });
  const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = filename; a.click(); URL.revokeObjectURL(a.href);
  toast('Datei heruntergeladen', 'ok');
}
async function openGerber() {
  if (window.showOpenFilePicker) {
    try {
      const [handle] = await window.showOpenFilePicker({ types: [{ description: 'Gerber / JSON', accept: { 'application/json': ['.gerber', '.json'] } }] });
      const file = await handle.getFile(); return JSON.parse(await file.text());
    } catch (err) { if (err && err.name === 'AbortError') return null; toast('Datei nicht lesbar', 'info'); return null; }
  }
  return new Promise(resolve => {
    const inp = document.createElement('input'); inp.type = 'file'; inp.accept = '.gerber,.json';
    inp.onchange = () => { const f = inp.files[0]; if (!f) return resolve(null); const r = new FileReader(); r.onload = () => { try { resolve(JSON.parse(r.result)); } catch (_) { toast('Datei nicht lesbar', 'info'); resolve(null); } }; r.readAsText(f); };
    inp.click();
  });
}
function exportTerminGerber(pid) {
  const p = findProjekt(pid); if (!p) return;
  const data = {
    format: 'gerber', formatVersion: 1, typ: 'terminprogramm', app: 'SubmitOne ' + APP_VERSION, exportiert: todayIso(),
    projekt: p.name || '', ort: p.ort || '', baustart: p.baustart || '', bauende: p.bauende || '', bezug: p.bezug || '',
    gewerke: (p.vergaben || []).map(v => ({ id: v.id, bkp: v.bkp || '', gewerk: v.gewerk || '', firma: v.firma || '', bauStart: v.bauStart || '', bauEnde: v.bauEnde || '', bestellfrist: v.bestellfrist || 0, nachfrist: v.nachfrist || 0, nachfristLabel: v.nachfristLabel || '', autoBalken: !!v.autoBalken, bauPhase: v.bauPhase || '', vorab: v.vorab ? { ...v.vorab } : null, vorgaenge: (v.vorgaenge || []).map(o => ({ id: o.id, titel: o.titel, start: o.start || '', ende: o.ende || '' })) })),
    ganttLinks: JSON.parse(JSON.stringify(p.ganttLinks || [])),
    regeln: JSON.parse(JSON.stringify(p.regeln || [])),
    sitzungsraster: p.sitzungsraster ? JSON.parse(JSON.stringify(p.sitzungsraster)) : null,
    feiertage: { kanton: p.kanton || '', brueckenAuffahrt: !!p.brueckenAuffahrt, extra: p.feiertageExtra || [], aus: p.feiertageAus || [] },
  };
  const safe = (p.name || 'terminprogramm').replace(/[^\w\-]+/g, '_').slice(0, 50);
  saveGerber(safe + '_terminprogramm.gerber', data);
}
// Terminprogramm aus .gerber einlesen → IMMER als neue Version (Snapshot inkl. Verknüpfungen); Gewerke werden über id bzw. BKP+Bezeichnung zugeordnet
async function importTerminGerber(pid) {
  const p = findProjekt(pid); if (!p) return;
  const data = await openGerber(); if (!data) return;
  if (data.typ !== 'terminprogramm' || !Array.isArray(data.gewerke)) { toast('Keine Terminprogramm-Datei (.gerber)', 'info'); return; }
  terminVersList(p);
  const byId = {}, byKey = {};
  (p.vergaben || []).forEach(v => { byId[v.id] = v; byKey[(v.bkp || '') + '|' + (v.gewerk || '')] = v; });
  const idMap = {}; const snapV = [];
  (data.gewerke || []).forEach(g => {
    const m = byId[g.id] || byKey[(g.bkp || '') + '|' + (g.gewerk || '')]; if (!m) return;
    idMap[g.id] = m.id;
    snapV.push({ id: m.id, bauStart: g.bauStart || '', bauEnde: g.bauEnde || '', bestellfrist: g.bestellfrist || 0, nachfrist: g.nachfrist || 0, nachfristLabel: g.nachfristLabel || '', autoBalken: !!g.autoBalken, bauPhase: g.bauPhase || '', vorab: g.vorab ? { ...g.vorab } : null, vorgaenge: (g.vorgaenge || []).map(o => ({ id: o.id, titel: o.titel, start: o.start || '', ende: o.ende || '' })) });
  });
  if (!snapV.length) { toast('Keine passenden Gewerke gefunden (BKP/Bezeichnung stimmen nicht überein)', 'info'); return; }
  const remapKey = k => { if (idMap[k]) return idMap[k]; const i = String(k).indexOf('/'); if (i > 0 && idMap[k.slice(0, i)]) return idMap[k.slice(0, i)] + k.slice(i); return idMap[k] === undefined && byId[k] ? k : null; };
  const links = (data.ganttLinks || []).map(l => { const f = remapKey(l.from), t = remapKey(l.to); return (f && t) ? { ...l, from: f, to: t } : null; }).filter(Boolean);
  const snapshot = { vergaben: snapV, ganttLinks: links, regeln: JSON.parse(JSON.stringify(data.regeln || [])), sitzungsraster: data.sitzungsraster ? JSON.parse(JSON.stringify(data.sitzungsraster)) : null, baustart: data.baustart || '', bauende: data.bauende || '', bezug: data.bezug || '' };
  tvSyncAktiv(p);   // aktuellen Stand in der aktiven Version sichern
  const nv = { id: uid('tv'), name: 'Import ' + fmtDate(todayIso()), datum: todayIso(), gesperrt: false, snapshot };
  p.terminVersionen.push(nv);   // als neue Version anlegen, aber NICHT sofort aktivieren
  save(); rerenderGantt(pid);
  toast('Importiert als Version „' + nv.name + '" (' + snapV.length + ' Gewerke, ' + links.length + ' Verknüpfungen) – Vergleich wird gezeigt', 'info');
  tvSwitch(pid, nv.id);   // zeigt den Vergleich/Achtung-Dialog – übernommen erst nach Bestätigung
}
function exportProjektGerber(pid) {
  const p = findProjekt(pid); if (!p) return;
  const data = { format: 'gerber', formatVersion: 1, typ: 'projekt', app: 'SubmitOne ' + APP_VERSION, exportiert: todayIso(), projekt: JSON.parse(JSON.stringify(p)) };
  const safe = (p.name || 'projekt').replace(/[^\w\-]+/g, '_').slice(0, 50);
  saveGerber(safe + '.gerber', data);
}
function addProjektFromGerber(data) {
  const proj = (data && data.typ === 'projekt' && data.projekt) ? data.projekt : ((data && data.id && data.vergaben) ? data : null);
  if (!proj) { toast('Keine gültige .gerber-Projektdatei', 'info'); return; }
  const np = JSON.parse(JSON.stringify(proj)); np.id = uid('p'); np.name = (np.name || 'Projekt') + ' (importiert)';
  state.projekte = state.projekte || []; state.projekte.push(np);
  save(); toast('Projekt importiert: ' + np.name, 'ok'); go('#/projekt/' + np.id);
}
async function importProjektGerber() { const data = await openGerber(); if (data) addProjektFromGerber(data); }
// Per Doppelklick geöffnete .gerber-Datei (installierte PWA) übernehmen
function initGerberLaunch() {
  if (!('launchQueue' in window)) return;
  try {
    window.launchQueue.setConsumer(async params => {
      if (!params || !params.files || !params.files.length) return;
      try { const file = await params.files[0].getFile(); addProjektFromGerber(JSON.parse(await file.text())); } catch (_) { toast('Datei nicht lesbar', 'info'); }
    });
  } catch (_) {}
}

