/* ============================================================
   HEADLESS-SELBSTTEST · Suite-Kern (S0.1)
   Aufruf:  node test/selftest-node.js   → prüft reine Kernlogik ohne Browser.
   Nur pure Funktionen testen (keine DOM-/State-Abhängigkeit).
   ============================================================ */
function selfTest() {
  const R = []; let pass = 0, fail = 0;
  const ok = (name, cond, msg) => { const good = !!cond; R.push({ name, ok: good, msg: good ? '' : (msg || '') }); good ? pass++ : fail++; };
  const eq = (name, got, exp) => ok(name, JSON.stringify(got) === JSON.stringify(exp), 'erwartet ' + JSON.stringify(exp) + ', bekam ' + JSON.stringify(got));

  // Text / ID
  eq('esc maskiert HTML', esc('<a>&"\''), '&lt;a&gt;&amp;&quot;&#39;');
  ok('uid mit Prefix', /^k_[a-z0-9]+$/.test(uid('k')));

  // Geld
  eq('chf(null) = –', chf(null), '–');
  eq('chf(0)', chf(0), 'CHF 0');
  eq('money(null) = –', money(null), '–');
  eq('money(5.5)', money(5.5), '5.50');
  eq('money(0)', money(0), '0.00');
  eq('chfShort(0) = –', chfShort(0), '–');
  eq('chfShort(500)', chfShort(500), '500');
  eq('chfShort(2 Mio.)', chfShort(2e6), '2 Mio.');

  // Datum
  eq('fmtDate leer', fmtDate(''), '–');
  eq('fmtDate CH', fmtDate('2026-06-09'), '09.06.2026');
  eq('addDays +1', addDays('2026-06-09', 1), '2026-06-10');
  eq('addDays Monatswechsel', addDays('2026-06-30', 1), '2026-07-01');
  eq('addDays -1 Jahreswechsel', addDays('2026-01-01', -1), '2025-12-31');
  eq('isoOf', isoOf(new Date(2026, 5, 9)), '2026-06-09');
  eq('dayDiffISO', dayDiffISO('2026-06-01', '2026-06-10'), 9);
  eq('parseDateFlexible dd.mm.yyyy', parseDateFlexible('9.6.2026'), '2026-06-09');
  eq('parseDateFlexible yyyy-m-d', parseDateFlexible('2026-6-9'), '2026-06-09');
  eq('parseDateFlexible ddmmyy', parseDateFlexible('090626'), '2026-06-09');
  eq('parseDateFlexible ungültig', parseDateFlexible('31.2.2026'), '');
  eq('parseDateFlexible Monatsname', parseDateFlexible('april 2026'), '2026-04-01');
  eq('parseDateFlexible Saison', parseDateFlexible('sommer 2026'), '2026-06-01');

  // BKP
  eq('parseBkp mit Label', parseBkp('211.5 Baumeister'), { code: '211.5', label: 'Baumeister' });
  eq('parseBkp nur Code', parseBkp('211'), { code: '211', label: '' });
  eq('bkpBase', bkpBase('211.5'), '211');
  ok('bkpCmp Reihenfolge', bkpCmp('211', '212') < 0);
  eq('bkpCmp leer nach hinten', bkpCmp('', '211'), 1);

  // Domänen-Rechnung (pur)
  eq('teilSumme summiert (auch String)', teilSumme({ teilvergaben: [{ betrag: 100 }, { betrag: '50' }] }), 150);
  const gs = gewerkeSorted({ vergaben: [{ bkp: '212', gewerk: 'B' }, { bkp: '211', gewerk: 'A' }] });
  eq('gewerkeSorted nach BKP', gs.map(v => v.bkp), ['211', '212']);

  // Firmen-UID
  eq('fmtUid formatiert', fmtUid('CHE123456789'), 'CHE-123.456.789');
  eq('fmtUid leer', fmtUid(''), '');

  // --- Geschäftskritische Zahlen: Nachträge, Rundung, Zahlungsplan, Kostenzeile, Versions-Diff ---
  eq('nachtragSumme nur genehmigt', nachtragSumme({ nachtraege: [{ status: 'genehmigt', betrag: 500 }, { status: 'offen', betrag: 999 }, { status: 'genehmigt', betrag: 100 }] }), 600);
  eq('rapportSumme', rapportSumme({ rapporte: [{ betrag: 200 }, { betrag: 50 }] }), 250);
  eq('budgetDelta (Ist − Budget)', budgetDelta({ budgetposten: [{ betrag: 1000, ist: 1200 }, { betrag: 500 }] }), 200);
  eq('schlussSumme', schlussSumme({ betrag: 10000, nachtraege: [{ status: 'genehmigt', betrag: 500 }], rapporte: [{ betrag: 200 }], budgetposten: [{ betrag: 1000, ist: 1200 }] }), 10900);
  eq('rp5 Rappen auf', rp5(12.34), 12.35);
  eq('rp5 Rappen ab', rp5(12.31), 12.30);
  ok('isVergeben true', isVergeben({ status: 'vergeben' }));
  ok('isVergeben false (Start)', !isVergeben({ status: VERGABE_STATUS[0].key }));

  // Kostenzeile: nur genehmigte Nachträge + Rapporte fliessen in die Prognose (offener Nachtrag zählt NICHT)
  const zk = kostenZeile({ status: 'vergeben', betrag: 10000, nachtraege: [{ status: 'genehmigt', betrag: 500 }, { status: 'offen', betrag: 999 }], rapporte: [{ betrag: 200 }] });
  eq('kostenZeile prognose', zk.prognose, 10700);
  eq('kostenZeile endsumme', zk.endsumme, 10700);
  eq('kostenZeile bezahlt', zk.bezahlt, 0);
  eq('kostenZeile offen', zk.offen, 10700);

  // Zahlungsplan-Rechnung (Prozente → Rappen-gerundete Beträge)
  const zp = zahlungsplanCalc({ betrag: 100000, phasen: [{ pct: 30 }, { pct: 40 }, { pct: 30 }] });
  eq('zahlungsplan Raten', zp.rows.map(r => r.betrag), [30000, 40000, 30000]);
  eq('zahlungsplan pctSum', zp.pctSum, 100);
  eq('zahlungsplan total', zp.total, 100000);
  eq('zahlungsplan kumuliert', zp.rows[2].cum, 100);

  // Kosten-Versions-Diff (Vergleich zweier Stände)
  const dA = { positionen: [{ id: 1, prognose: 1000, bezahlt: 0, gewerk: 'A', bkp: '211' }] };
  const dB = { positionen: [{ id: 1, prognose: 1200, bezahlt: 0, gewerk: 'A', bkp: '211' }, { id: 2, prognose: 500, bezahlt: 0, gewerk: 'B', bkp: '212' }] };
  const kd = kostenDiff(dA, dB);
  eq('kostenDiff totA', kd.totA, 1000);
  eq('kostenDiff totB', kd.totB, 1700);
  eq('kostenDiff dTot', kd.dTot, 700);
  eq('kostenDiff Zeilenzahl', kd.rows.length, 2);
  eq('kostenDiff changed dProg', (kd.rows.find(r => r.status === 'changed') || {}).dProg, 200);
  ok('kostenDiff neu erkannt', kd.rows.some(r => r.status === 'new'));

  // Termin↔Kosten-Verknüpfung (S1.1-Kern): Prognose jeder Vergabe wird über die Bau-Monate verteilt
  const bpProj = { vergaben: [
    { id: 1, bkp: '211', gewerk: 'A', status: 'vergeben', betrag: 12000, bauStart: '2026-01-01', bauEnde: '2026-03-31' },  // 3 Monate → 4000/Mt
    { id: 2, bkp: '212', gewerk: 'B', status: 'vergeben', betrag: 6000, bauStart: '2026-02-01', bauEnde: '2026-02-28' },   // 1 Monat → 6000
    { id: 3, bkp: '213', gewerk: 'C', status: 'vergeben', betrag: 5000 }                                                    // ohne Termin → fehlend
  ] };
  const bp = bauherrPlan(bpProj);
  eq('bauherrPlan Monatskeys', bp.monate.map(m => m.key), ['2026-01', '2026-02', '2026-03']);
  eq('bauherrPlan Monatsbeträge', bp.monate.map(m => m.betrag), [4000, 10000, 4000]);   // Feb: 4000 (A) + 6000 (B)
  eq('bauherrPlan kumuliert Ende', bp.monate[2].cum, 18000);
  eq('bauherrPlan Total (nur terminiert)', bp.total, 18000);
  eq('bauherrPlan fehlend (ohne Termin)', bp.fehlend.length, 1);

  // Ausschreibung/Nachkontrolle (S1.2-Kern): Fristen-Ampel + nächste offene Frist (relativ zu heute)
  eq('fristClass überfällig', fristClass(addDays(todayIso(), -1), false), 'over');
  eq('fristClass Warnung ≤7d', fristClass(addDays(todayIso(), 3), false), 'warn');
  eq('fristClass fern', fristClass(addDays(todayIso(), 30), false), '');
  eq('fristClass erledigt → keine', fristClass(addDays(todayIso(), -5), true), '');
  eq('fristText leer', fristText('', false), '–');
  ok('fristText „heute"', /heute/.test(fristText(addDays(todayIso(), 0), false)));
  ok('fristText „überf."', /überf\./.test(fristText(addDays(todayIso(), -2), false)));
  ok('fristText „in 5d"', /in 5d/.test(fristText(addDays(todayIso(), 5), false)));
  eq('naechsteFrist früheste offene', naechsteFrist({ vergaben: [{ frist: '2026-03-01', status: 'offen' }, { frist: '2026-01-15', status: 'offen' }, { frist: '2020-01-01', status: 'abgeschlossen' }] }), '2026-01-15');
  ok('naechsteFrist ohne Frist → null', naechsteFrist({ vergaben: [{ status: 'offen' }] }) === null);

  // --- Randfälle / Härtung (Bug-Hunt) ---
  eq('parseDateFlexible 0.0.0 ungültig', parseDateFlexible('0.0.0'), '');
  eq('parseDateFlexible 99.99.99 ungültig', parseDateFlexible('99.99.99'), '');
  eq('parseDateFlexible leer', parseDateFlexible(''), '');
  eq('addDays Schaltjahr 29.2.', addDays('2024-02-28', 1), '2024-02-29');
  eq('addDays Nicht-Schaltjahr', addDays('2023-02-28', 1), '2023-03-01');
  ok('chf negativ enthält Minus', chf(-5000).includes('-'));
  eq('money negativ', money(-3.5), '-3.50');
  eq('nachtragSumme leeres Objekt', nachtragSumme({}), 0);
  eq('kostenZeile ohne Vergabe → Schätzung', kostenZeile({ status: VERGABE_STATUS[0].key, schaetzung: 8000 }).prognose, 8000);
  eq('zahlungsplanCalc pct≠100 → Teil-Total', zahlungsplanCalc({ betrag: 100000, phasen: [{ pct: 30 }, { pct: 30 }] }).total, 60000);
  eq('kostenDiff entfernt erkannt', kostenDiff({ positionen: [{ id: 9, prognose: 500, gewerk: 'X', bkp: '2' }] }, { positionen: [] }).rows[0].status, 'removed');

  // Undo (nicht kaputtbar): save() sichert VOR der Änderung; eine Löschung ist rückholbar (Kernlogik, ohne DOM-Render)
  { const _st = state, _us = undoStack, _rs = redoStack, _ls = lastSnap, _la = lastSnapAt;
    try {
      state = { projekte: [{ id: 'p1', name: 'X', vergaben: [{ id: 'v1' }, { id: 'v2' }] }], kontakte: [], dokumente: [], buero: {} };
      lastSnap = JSON.stringify(state); lastSnapAt = 0; undoStack = []; redoStack = []; undoing = false;
      state.projekte[0].vergaben = state.projekte[0].vergaben.filter(v => v.id !== 'v2'); save();   // löschen + speichern
      eq('Undo: Snapshot angelegt', undoStack.length, 1);
      eq('Undo: nach Löschen 1 Vergabe', state.projekte[0].vergaben.length, 1);
      eq('Undo: Snapshot enthält Vor-Zustand (2)', JSON.parse(undoStack[0]).projekte[0].vergaben.length, 2);
      state = JSON.parse(undoStack.pop());   // Kern der undo()-Wiederherstellung
      eq('Undo (Wiederherstellung): Vergabe zurück (2)', state.projekte[0].vergaben.length, 2);
    } catch (e) { ok('Undo-Kernlogik ohne Fehler', false, (e && e.message) || 'Fehler'); }
    finally { state = _st; undoStack = _us; redoStack = _rs; lastSnap = _ls; lastSnapAt = _la; undoing = false; }
  }

  // Migration („für immer": alte Daten öffnen → der Übersetzer ergänzt fehlende Felder + wandelt Altformate)
  { const _st = state;
    try {
      state = { projekte: [{ id: 'p1', name: 'Alt',
        entscheidungen: [{ id: 'e1', status: 'entschieden', thema: 'Küche neu' }],
        vergaben: [{ id: 'v1', offerten: [{ firma: 'A', betrag: 100 }] }],
        protokolle: [{ id: 'pr1', traktanden: [{ eintraege: [{ text: 'x', verantwortlich: 'B' }] }] }] }] };
      migrate();
      const p = state.projekte[0];
      ok('Migration: fehlende Top-Arrays ergänzt', Array.isArray(state.kontakte) && Array.isArray(state.dokumente));
      ok('Migration: Projekt-Felder ergänzt', Array.isArray(p.geschosseListe) && Array.isArray(p.auflagen) && Array.isArray(p.mitglieder) && Array.isArray(p.termine) && !!p.finanz);
      eq('Migration: Status entschieden→gewaehlt', p.entscheidungen[0].status, 'gewaehlt');
      eq('Migration: BKP aus Thema (Küche→258)', p.entscheidungen[0].bkp, '258');
      ok('Migration: offerten→eingeladene (Altformat)', !!p.vergaben[0].eingeladene && p.vergaben[0].offerten === undefined && p.vergaben[0].eingeladene[0].status === 'offeriert' && p.vergaben[0].eingeladene[0].betrag === 100);
      const it = p.protokolle[0].traktanden[0].eintraege[0];
      ok('Migration: Traktanden-Defaults (art/erledigt/uebertragen)', it.art === 'pendenz' && it.erledigt === false && it.uebertragen === false);
    } catch (e) { ok('Migration ohne Fehler', false, (e && e.message) || 'Fehler'); }
    finally { state = _st; }
  }

  // Ladepfad „nicht kaputtbar": beschädigte Daten dürfen NICHT mit Demo überschrieben werden
  eq('initDecision: gültige Daten → nutzen', initDecision({ projekte: [] }, false), 'use');
  eq('initDecision: Lesefehler → Demo behalten (nichts überschreiben)', initDecision(null, true), 'keep-demo');
  eq('initDecision: wirklich leer → Erststart committen', initDecision(null, false), 'commit-demo');

  // Persona-Schnellzugriff: rollenspezifische Wege, gültiger Fallback
  ok('personaActions Bauleiter → Erfassen+Pendenzen', personaActions('bauleiter').some(a => a.href === '#/erfassen') && personaActions('bauleiter').some(a => a.href === '#/pendenzen'));
  ok('personaActions Finanz → Honorar', personaActions('finanz').some(a => a.href === '#/honorar'));
  ok('personaActions unbekannt → Fallback alle (mit Neues Projekt)', personaActions('xyz').length === personaActions('alle').length && personaActions('alle').some(a => a.act === 'new-projekt'));
  ok('personaOnboardCard: 4 Rollen + Umschauen', ['bauleiter', 'architekt', 'finanz', 'sekretariat', 'alle'].every(k => new RegExp('data-persona="' + k + '"').test(personaOnboardCard())) && /ob-choice/.test(personaOnboardCard()) && /ob-skip/.test(personaOnboardCard()));
  ok('personaPrimary: Overview zuerst + 6 Reiter je Rolle', ['alle', 'bauleiter', 'architekt', 'finanz', 'sekretariat'].every(k => personaPrimary(k)[0] === 'overview' && personaPrimary(k).length === 6));
  ok('personaPrimary Finanz → Kosten+Rechnungen primär', personaPrimary('finanz').includes('kosten') && personaPrimary('finanz').includes('rechnungen'));
  ok('personaPrimary Bauleiter → Pendenzen+Protokolle primär', personaPrimary('bauleiter').includes('pendenzen') && personaPrimary('bauleiter').includes('protokolle'));
  ok('personaErfassenOrder Finanz → Rechnung zuerst', personaErfassenOrder('finanz')[0] === 'rechnung');
  ok('personaErfassenOrder Bauleiter → Pendenz zuerst', personaErfassenOrder('bauleiter')[0] === 'pendenz');
  ok('personaErfassenOrder vollständig (7 Arten, keine Dubletten)', (() => { const o = personaErfassenOrder('architekt'); return o.length === 7 && new Set(o).size === 7; })());

  // Leerzustand: erweiterter emptyState (Sub-Text + Aktions-Knopf) rückwärtskompatibel
  ok('emptyState schlicht (nur Icon+Text)', /class="empty"/.test(emptyState('x', 'Leer')) && !/e-cta/.test(emptyState('x', 'Leer')) && !/e-sub/.test(emptyState('x', 'Leer')));
  ok('emptyState mit Sub + CTA', (() => { const h = emptyState('x', 'Leer', 'Hinweis', { label: '+ Neu', act: 'new-projekt' }); return /e-sub/.test(h) && /data-act="new-projekt"/.test(h) && /\+ Neu/.test(h); })());

  return { R, pass, fail };
}
